// modules/Problems/services/ProblemsService.js

async function solve({ difficulty, limit, tags }) {
  // Normalize and parse tags filter
  let normalizedTags = [];
  if (tags !== undefined) {
    if (Array.isArray(tags)) {
      normalizedTags = tags
        .flatMap(t => (typeof t === 'string' ? t.split(',') : []))
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    } else if (typeof tags === 'string') {
      normalizedTags = tags
        .split(',')
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    }
  }

  // Build base query with difficulty filter if provided
  let query = `
    SELECT p.*
    FROM problems p
  `;
  const params = [];
  const whereClauses = [];

  if (normalizedTags.length > 0) {
    query += `
      JOIN problem_tags pt ON pt.problem_id = p.id
    `;
    whereClauses.push(`LOWER(pt.tag) = ANY($${params.length + 1})`);
    params.push(normalizedTags);
  }

  if (difficulty !== undefined) {
    whereClauses.push(`p.difficulty = $${params.length + 1}`);
    params.push(difficulty);
  }

  if (whereClauses.length > 0) {
    query += ` WHERE ${whereClauses.join(' AND ')} `;
  }

  query += ` GROUP BY p.id ORDER BY p.id ASC `;

  if (limit !== undefined) {
    query += ` LIMIT $${params.length + 1} `;
    params.push(limit);
  }

  // Execute query to get filtered problems
  const problems = await db.query(query, params);

  // Prepare metadata with appliedTags normalized
  const metadata = {
    appliedTags: normalizedTags.length > 0 ? normalizedTags : undefined,
  };

  return { problems: problems.rows, metadata };
}

module.exports = { solve };
